import React from "react";

function Dashboard() {
  return (
    <div style={styles.container}>
      <h1>Dashboard Loaded ✅</h1>
      <p>Welcome to your Mental Health Assistant</p>

      <div style={styles.cardGrid}>
        <div style={styles.card}>General Chat</div>
        <div style={styles.card}>Mood Tracker</div>
        <div style={styles.card}>Sleep Tracker</div>
        <div style={styles.card}>Crisis Support</div>
        <div style={styles.card}>Chat History</div>
        <div style={styles.card}>Logout</div>
      </div>
    </div>
  );
}

const styles = {
  container: {
    minHeight: "100vh",
    padding: "40px",
    background: "#eef2ff",
    fontFamily: "Arial",
    textAlign: "center",
  },
  cardGrid: {
    display: "grid",
    gridTemplateColumns: "repeat(auto-fit, minmax(200px, 1fr))",
    gap: "20px",
    marginTop: "30px",
  },
  card: {
    padding: "30px",
    background: "#fff",
    borderRadius: "16px",
    boxShadow: "0 10px 20px rgba(0,0,0,0.1)",
    cursor: "pointer",
  },
};

export default Dashboard;
